import{c as s,Q as n,j as l,m as e}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"多机房与异地多活","description":"","frontmatter":{},"headers":[],"relativePath":"systemDesign/25-多机房与异地多活.md","filePath":"systemDesign/25-多机房与异地多活.md","lastUpdated":1778496697000}'),p={name:"systemDesign/25-多机房与异地多活.md"};function i(t,a,o,r,c,h){return n(),l("div",null,[...a[0]||(a[0]=[e(`<h1 id="多机房与异地多活" tabindex="-1">多机房与异地多活 <a class="header-anchor" href="#多机房与异地多活" aria-label="Permalink to &quot;多机房与异地多活&quot;">​</a></h1><p>单机房终究有上限——电力、散热、带宽、政策、灾难。<strong>真正的大型互联网架构都是多机房</strong>:阿里 / 字节 / 腾讯 / 美团 都是 5+ 机房同时跑业务。但<strong>多机房不是&quot;复制一份就完了&quot;</strong> —— 同步延迟、跨机房一致性、流量调度、容灾切换 都是地狱难题。这一篇讲清楚<strong>多机房的四种模式</strong>(冷备 / 双活 / 多活 / Cell 单元化)、<strong>单元化</strong>(Cell)的本质、以及<strong>为什么&quot;异地多活&quot;是当今互联网的最高架构挑战</strong>。</p><blockquote><p>一句话先记住:<strong>多机房的本质是&quot;跨光纤距离 vs 数据一致性&quot;的取舍</strong>——同城双活近(2-5ms 延迟),数据强一致;异地多活远(30ms+),只能最终一致。<strong>Cell 单元化是解决跨机房写一致性的工程艺术</strong>——把用户分桶,每个桶(Cell)在一个机房自包含运行,跨 Cell 只走异步同步。<strong>异地多活是&quot;组织能力&quot;而不是&quot;技术能力&quot;</strong> —— 没有整套发布、监控、演练体系支撑,多活就是炸弹。</p></blockquote><hr><h2 id="一、为什么需要多机房" tabindex="-1">一、为什么需要多机房 <a class="header-anchor" href="#一、为什么需要多机房" aria-label="Permalink to &quot;一、为什么需要多机房&quot;">​</a></h2><h3 id="_1-1-单机房的物理上限" tabindex="-1">1.1 单机房的物理上限 <a class="header-anchor" href="#_1-1-单机房的物理上限" aria-label="Permalink to &quot;1.1 单机房的物理上限&quot;">​</a></h3><ul><li><strong>电力</strong>:单机房 10-30 MW 上限</li><li><strong>散热</strong>:单数据中心 5000-10000 服务器后散热成本爆炸</li><li><strong>带宽</strong>:单机房出口 100 Gbps-1 Tbps 上限</li><li><strong>空间</strong>:寸土寸金,机柜租金贵</li></ul><h3 id="_1-2-灾难恢复" tabindex="-1">1.2 灾难恢复 <a class="header-anchor" href="#_1-2-灾难恢复" aria-label="Permalink to &quot;1.2 灾难恢复&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事故案例:</span></span>
<span class="line"><span>  2015 年 阿里杭州机房光缆被挖,支付宝瘫痪 4 小时</span></span>
<span class="line"><span>  2017 年 GitLab 误删数据库,丢 6 小时数据</span></span>
<span class="line"><span>  2021 年 Fastly CDN 故障,全球互联网半小时大面积瘫痪</span></span>
<span class="line"><span>  2024 年 某云国内机房地震,双活失效</span></span></code></pre></div><p><strong>单机房 = 单点故障</strong>。<strong>金融、医疗、政务</strong>强制要求多机房。</p><h3 id="_1-3-政策合规" tabindex="-1">1.3 政策合规 <a class="header-anchor" href="#_1-3-政策合规" aria-label="Permalink to &quot;1.3 政策合规&quot;">​</a></h3><ul><li>中国数据出境受限 → 海外业务必须海外有机房</li><li>欧盟 GDPR → 欧洲用户数据必须存欧洲</li><li>各种行业要求&quot;两地三中心&quot;</li></ul><h3 id="_1-4-用户延迟" tabindex="-1">1.4 用户延迟 <a class="header-anchor" href="#_1-4-用户延迟" aria-label="Permalink to &quot;1.4 用户延迟&quot;">​</a></h3><ul><li>海外用户访问国内 200ms+</li><li>必须就近接入</li></ul><hr><h2 id="二、多机房的四种模式" tabindex="-1">二、多机房的四种模式 <a class="header-anchor" href="#二、多机房的四种模式" aria-label="Permalink to &quot;二、多机房的四种模式&quot;">​</a></h2><p>按复杂度从低到高:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>冷备     → 主用 A,B 完全闲置,出事手动切</span></span>
<span class="line"><span>温备     → 主用 A,B 跑着但不接流量</span></span>
<span class="line"><span>同城双活 → A B 都接流量,数据强一致</span></span>
<span class="line"><span>异地多活 → A B C... 都接流量,数据最终一致</span></span>
<span class="line"><span>单元化   → 异地多活的极致,用户分桶到 Cell</span></span></code></pre></div><hr><h2 id="三、模式-1-冷备-传统金融用" tabindex="-1">三、模式 1:冷备(传统金融用) <a class="header-anchor" href="#三、模式-1-冷备-传统金融用" aria-label="Permalink to &quot;三、模式 1:冷备(传统金融用)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 机房 (Active):           B 机房 (Cold Standby):</span></span>
<span class="line"><span>  完整业务运行                 服务器在线但不跑业务</span></span>
<span class="line"><span>  数据写入                     定期复制 A 的数据</span></span>
<span class="line"><span>  流量进来                     流量进不来</span></span>
<span class="line"><span></span></span>
<span class="line"><span>A 挂了:</span></span>
<span class="line"><span>  人工评估 → 切 DNS → B 启动业务 → 数据可能丢失最后一段</span></span></code></pre></div><p><strong>优点</strong>:简单,B 的硬件/数据正确性容易保证。 <strong>缺点</strong>:</p><ul><li>B 平时不发挥作用,<strong>100% 浪费成本</strong></li><li>切换需要几小时(测试 + 启动)</li><li>数据丢失(异步复制)</li></ul><p><strong>适合</strong>:<strong>银行核心</strong>——可用性要求 5 分钟,但不能用&quot;双活&quot;(强一致难保证),用冷备 + 严密演练。</p><hr><h2 id="四、模式-2-同城双活-主流互联网" tabindex="-1">四、模式 2:同城双活(主流互联网) <a class="header-anchor" href="#四、模式-2-同城双活-主流互联网" aria-label="Permalink to &quot;四、模式 2:同城双活(主流互联网)&quot;">​</a></h2><p>A B 在同一城市(20 km 内),<strong>两个机房都接流量</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       用户</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>        DNS / Anycast</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>   ┌────┴────┐</span></span>
<span class="line"><span>   ↓         ↓</span></span>
<span class="line"><span>A 机房    B 机房</span></span>
<span class="line"><span>(50%)    (50%)</span></span>
<span class="line"><span>   ↑         ↑</span></span>
<span class="line"><span>   └────┬────┘</span></span>
<span class="line"><span>   共享 / 同步 DB</span></span>
<span class="line"><span>   (主从 / 半同步)</span></span></code></pre></div><h3 id="_4-1-数据怎么处理" tabindex="-1">4.1 数据怎么处理? <a class="header-anchor" href="#_4-1-数据怎么处理" aria-label="Permalink to &quot;4.1 数据怎么处理?&quot;">​</a></h3><p><strong>方案 A:共享 DB</strong>(同城两机房之间 &lt; 5ms)</p><p>A 和 B 应用层都连同一个 DB(在 A 或 B 机房)。</p><ul><li><strong>优点</strong>:强一致</li><li><strong>缺点</strong>:DB 单机房,挂了双活变伪双活</li></ul><p><strong>方案 B:DB 主从同步</strong></p><ul><li>A 用本地 DB(主),B 用本地 DB(从)</li><li>写都路由到 A 的主库,读各自就近读</li><li>A 挂了 → B 升主</li></ul><p><strong>方案 C:DB 同城双主</strong>(MySQL Group Replication / 阿里 OceanBase)</p><ul><li>A B 都能写</li><li>通过 Paxos / Raft 保证强一致</li><li>写延迟略增(等多数派)</li></ul><blockquote><p><strong>同城双活的甜蜜区</strong>:延迟低、可强一致、容灾足够(罕见两机房同时挂)。<strong>99% 的中型互联网都是同城双活</strong>。</p></blockquote><h3 id="_4-2-流量调度" tabindex="-1">4.2 流量调度 <a class="header-anchor" href="#_4-2-流量调度" aria-label="Permalink to &quot;4.2 流量调度&quot;">​</a></h3><ul><li>平时 50/50</li><li>A 性能下降 → 调成 30/70</li><li>A 完全挂 → 100% 切 B(LB / DNS 自动)</li></ul><hr><h2 id="五、模式-3-异地多活-顶级架构" tabindex="-1">五、模式 3:异地多活(顶级架构) <a class="header-anchor" href="#五、模式-3-异地多活-顶级架构" aria-label="Permalink to &quot;五、模式 3:异地多活(顶级架构)&quot;">​</a></h2><p>A B 在不同城市(几百~几千公里)——<strong>延迟 30-100ms</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       全球 / 全国用户</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>       DNS / Anycast(就近)</span></span>
<span class="line"><span>              ↓</span></span>
<span class="line"><span>   ┌──────────┼──────────┐</span></span>
<span class="line"><span>   ↓          ↓          ↓</span></span>
<span class="line"><span>北京机房   上海机房    深圳机房</span></span>
<span class="line"><span>   ↕          ↕          ↕</span></span>
<span class="line"><span>   异步数据同步 (延迟 100ms - 几秒)</span></span></code></pre></div><h3 id="_5-1-异地的核心难点-写延迟" tabindex="-1">5.1 异地的核心难点:写延迟 <a class="header-anchor" href="#_5-1-异地的核心难点-写延迟" aria-label="Permalink to &quot;5.1 异地的核心难点:写延迟&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>北京用户写:</span></span>
<span class="line"><span>  本地写北京机房     ✓ 1ms</span></span>
<span class="line"><span>  同步到上海机房     ✗ 30ms</span></span>
<span class="line"><span>  同步到深圳机房     ✗ 50ms</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果&quot;等所有机房确认&quot;才返回:</span></span>
<span class="line"><span>  写延迟 = 50ms+(用户卡)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>如果只等本地确认:</span></span>
<span class="line"><span>  写延迟 1ms</span></span>
<span class="line"><span>  但其他机房有 100ms-几秒&quot;看不到这个写&quot;</span></span></code></pre></div><p><strong>取舍</strong>:<strong>牺牲一致性换性能</strong>。</p><h3 id="_5-2-异地数据冲突" tabindex="-1">5.2 异地数据冲突 <a class="header-anchor" href="#_5-2-异地数据冲突" aria-label="Permalink to &quot;5.2 异地数据冲突&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>北京用户改头像 → 头像 = &quot;A.jpg&quot;</span></span>
<span class="line"><span>同时上海用户(其实是同一个账号在不同设备)→ 头像 = &quot;B.jpg&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>异步同步后:</span></span>
<span class="line"><span>  北京以为头像是 A</span></span>
<span class="line"><span>  上海以为头像是 B</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>谁赢?</span></span></code></pre></div><p><strong>冲突解决</strong>:</p><ul><li><strong>Last Write Wins(按时间戳)</strong>:简单但丢数据</li><li><strong>业务侧合并</strong>:复杂(不同字段不同策略)</li><li><strong>避免冲突</strong>:<strong>同一用户只在一个机房写</strong>(Cell 单元化)</li></ul><hr><h2 id="六、模式-4-cell-单元化-异地多活的终极形态" tabindex="-1">六、模式 4:Cell 单元化(异地多活的终极形态) <a class="header-anchor" href="#六、模式-4-cell-单元化-异地多活的终极形态" aria-label="Permalink to &quot;六、模式 4:Cell 单元化(异地多活的终极形态)&quot;">​</a></h2><p><strong>思想</strong>:<strong>用户分桶,每个桶(Cell)在一个机房自包含</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────── Cell-A (北京) ─────────┐</span></span>
<span class="line"><span>│ 完整业务: 应用 + DB + 缓存 + MQ │</span></span>
<span class="line"><span>│ 服务用户: user_id 0 ~ 1 亿      │</span></span>
<span class="line"><span>└────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────── Cell-B (上海) ─────────┐</span></span>
<span class="line"><span>│ 完整业务                       │</span></span>
<span class="line"><span>│ 服务用户: user_id 1 亿 ~ 2 亿  │</span></span>
<span class="line"><span>└────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────── Cell-C (深圳) ─────────┐</span></span>
<span class="line"><span>│ 完整业务                       │</span></span>
<span class="line"><span>│ 服务用户: user_id 2 亿 ~ 3 亿  │</span></span>
<span class="line"><span>└────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>跨 Cell:仅异步数据同步</span></span></code></pre></div><h3 id="_6-1-优势" tabindex="-1">6.1 优势 <a class="header-anchor" href="#_6-1-优势" aria-label="Permalink to &quot;6.1 优势&quot;">​</a></h3><ul><li><strong>每个 Cell 内部都强一致</strong>(本地操作)</li><li><strong>故障隔离</strong>:Cell-A 挂只影响 1/N 用户</li><li><strong>就近接入</strong>:用户路由到自己的 Cell</li><li><strong>水平扩展</strong>:加 Cell 即可</li></ul><h3 id="_6-2-难点" tabindex="-1">6.2 难点 <a class="header-anchor" href="#_6-2-难点" aria-label="Permalink to &quot;6.2 难点&quot;">​</a></h3><ul><li><strong>路由层</strong>:用户访问任何域名时,<strong>接入层必须知道他属于哪个 Cell</strong></li><li><strong>跨 Cell 数据</strong>:用户 A(Cell-A)给用户 B(Cell-B)发消息怎么办? → 写入 A 的 DB → 异步同步到 B → B 才看到</li></ul><h3 id="_6-3-阿里的-ldc-logical-data-center" tabindex="-1">6.3 阿里的 LDC(Logical Data Center) <a class="header-anchor" href="#_6-3-阿里的-ldc-logical-data-center" aria-label="Permalink to &quot;6.3 阿里的 LDC(Logical Data Center)&quot;">​</a></h3><p>阿里 2014 年开始的单元化,<strong>支撑双 11 流量</strong>:</p><ul><li>用户按 user_id % 100 分桶</li><li>每桶分配到某个 Cell</li><li>全国 5+ 个 Cell</li><li>每年双 11 之前做&quot;Cell 切换&quot;演练</li></ul><hr><h2 id="七、cell-化的工程细节" tabindex="-1">七、Cell 化的工程细节 <a class="header-anchor" href="#七、cell-化的工程细节" aria-label="Permalink to &quot;七、Cell 化的工程细节&quot;">​</a></h2><h3 id="_7-1-用户路由" tabindex="-1">7.1 用户路由 <a class="header-anchor" href="#_7-1-用户路由" aria-label="Permalink to &quot;7.1 用户路由&quot;">​</a></h3><p>用户登录后,<strong>接入层立刻知道他归哪个 Cell</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key:    user_route:{user_id}</span></span>
<span class="line"><span>value:  cell_id (A / B / C ...)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>路由层:</span></span>
<span class="line"><span>  if user.cell != current_cell:</span></span>
<span class="line"><span>    302 redirect to user.cell.domain</span></span></code></pre></div><p>或在 DNS 层做&quot;按用户 IP 返回不同 Cell 的 IP&quot;。</p><h3 id="_7-2-跨-cell-调用" tabindex="-1">7.2 跨 Cell 调用 <a class="header-anchor" href="#_7-2-跨-cell-调用" aria-label="Permalink to &quot;7.2 跨 Cell 调用&quot;">​</a></h3><p>跨 Cell 的请求<strong>不允许同步阻塞</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户在 Cell-A 给 Cell-B 用户发消息:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>错(同步):</span></span>
<span class="line"><span>  Cell-A → 实时调用 Cell-B 的 IM 服务</span></span>
<span class="line"><span>  跨机房 RPC → 30ms+ → 用户体验差</span></span>
<span class="line"><span></span></span>
<span class="line"><span>对(异步):</span></span>
<span class="line"><span>  Cell-A → 写入消息队列(本地)→ 立即返回</span></span>
<span class="line"><span>  消息队列 → 异步同步到 Cell-B → Cell-B 投递给用户</span></span></code></pre></div><h3 id="_7-3-跨-cell-数据一致性" tabindex="-1">7.3 跨 Cell 数据一致性 <a class="header-anchor" href="#_7-3-跨-cell-数据一致性" aria-label="Permalink to &quot;7.3 跨 Cell 数据一致性&quot;">​</a></h3><p><strong>全局数据</strong>(配置、商品库、字典)→ 所有 Cell 都有副本,异步复制:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>中心 → 推到 Cell-A、Cell-B、Cell-C</span></span>
<span class="line"><span>延迟几秒,但全局数据本来就不频繁变</span></span></code></pre></div><p><strong>用户数据</strong>(订单、消息)→ 主 Cell 写,其他 Cell 副本同步:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cell-A 用户的订单 → 主存储在 Cell-A</span></span>
<span class="line"><span>                 → 异步同步到 Cell-B、Cell-C(用于跨 Cell 查询和容灾)</span></span></code></pre></div><hr><h2 id="八、流量调度" tabindex="-1">八、流量调度 <a class="header-anchor" href="#八、流量调度" aria-label="Permalink to &quot;八、流量调度&quot;">​</a></h2><h3 id="_8-1-路由策略" tabindex="-1">8.1 路由策略 <a class="header-anchor" href="#_8-1-路由策略" aria-label="Permalink to &quot;8.1 路由策略&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>按用户:user_id 哈希到 Cell</span></span>
<span class="line"><span>按地理:北京用户进 Cell-A(就近)</span></span>
<span class="line"><span>按业务:核心业务双 Cell,边缘业务单 Cell</span></span>
<span class="line"><span>按 SKU:某些商品集中在某 Cell</span></span></code></pre></div><h3 id="_8-2-切流-关键能力" tabindex="-1">8.2 切流(关键能力) <a class="header-anchor" href="#_8-2-切流-关键能力" aria-label="Permalink to &quot;8.2 切流(关键能力)&quot;">​</a></h3><p>Cell-A 挂了 / 需要维护:<strong>把流量切到 Cell-B</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>切流前:</span></span>
<span class="line"><span>  Cell-A 50%, Cell-B 50%</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>切流过程(灰度):</span></span>
<span class="line"><span>  Cell-A 30%, Cell-B 70%</span></span>
<span class="line"><span>  Cell-A 10%, Cell-B 90%</span></span>
<span class="line"><span>  Cell-A 0%,  Cell-B 100%</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每一步等几分钟,确认指标正常再继续</span></span></code></pre></div><p><strong>关键</strong>:切流是<strong>毫秒级生效</strong>——通过路由表 + 配置中心推送,不用重启。</p><h3 id="_8-3-切流演练" tabindex="-1">8.3 切流演练 <a class="header-anchor" href="#_8-3-切流演练" aria-label="Permalink to &quot;8.3 切流演练&quot;">​</a></h3><p><strong>没演练过的切流肯定出事</strong>——阿里、字节都有定期演练:</p><ul><li>每月演练同城切流</li><li>每季度演练跨地域切流</li><li>每半年演练&quot;整个 Cell 模拟挂掉&quot;</li></ul><hr><h2 id="九、监控-多机房特有指标" tabindex="-1">九、监控:多机房特有指标 <a class="header-anchor" href="#九、监控-多机房特有指标" aria-label="Permalink to &quot;九、监控:多机房特有指标&quot;">​</a></h2><h3 id="_9-1-跨机房延迟" tabindex="-1">9.1 跨机房延迟 <a class="header-anchor" href="#_9-1-跨机房延迟" aria-label="Permalink to &quot;9.1 跨机房延迟&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cell-A → Cell-B 同步延迟</span></span>
<span class="line"><span>  正常 &lt; 1 秒</span></span>
<span class="line"><span>  &gt; 5 秒 报警</span></span>
<span class="line"><span>  &gt; 30 秒 P0</span></span></code></pre></div><h3 id="_9-2-数据一致性指标" tabindex="-1">9.2 数据一致性指标 <a class="header-anchor" href="#_9-2-数据一致性指标" aria-label="Permalink to &quot;9.2 数据一致性指标&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cell-A 和 Cell-B 的同一表数据校验</span></span>
<span class="line"><span>  每小时随机抽样比对</span></span>
<span class="line"><span>  发现差异立即查</span></span></code></pre></div><h3 id="_9-3-各-cell-容量" tabindex="-1">9.3 各 Cell 容量 <a class="header-anchor" href="#_9-3-各-cell-容量" aria-label="Permalink to &quot;9.3 各 Cell 容量&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cell-A CPU / Memory / DB QPS</span></span>
<span class="line"><span>  超过 70% 预警</span></span>
<span class="line"><span>  超过 85% 准备切流到其他 Cell</span></span></code></pre></div><hr><h2 id="十、典型公司的多活架构" tabindex="-1">十、典型公司的多活架构 <a class="header-anchor" href="#十、典型公司的多活架构" aria-label="Permalink to &quot;十、典型公司的多活架构&quot;">​</a></h2><h3 id="_10-1-阿里-ldc-rzone-gzone-czone" tabindex="-1">10.1 阿里:LDC + RZone / GZone / CZone <a class="header-anchor" href="#_10-1-阿里-ldc-rzone-gzone-czone" aria-label="Permalink to &quot;10.1 阿里:LDC + RZone / GZone / CZone&quot;">​</a></h3><ul><li><strong>RZone</strong>(Region Zone):用户数据按 user_id 分桶</li><li><strong>GZone</strong>(Global Zone):全局共享数据(商品库、配置),只读副本</li><li><strong>CZone</strong>(City Zone):城市级数据,本地化</li></ul><h3 id="_10-2-字节-多机房-cell" tabindex="-1">10.2 字节:多机房 Cell <a class="header-anchor" href="#_10-2-字节-多机房-cell" aria-label="Permalink to &quot;10.2 字节:多机房 Cell&quot;">​</a></h3><ul><li>国内:北京 + 上海 + 广州 + ...</li><li>海外:新加坡 + 美西 + ...</li><li>业务按用户分 Cell</li></ul><h3 id="_10-3-微信-三园区五机房" tabindex="-1">10.3 微信:三园区五机房 <a class="header-anchor" href="#_10-3-微信-三园区五机房" aria-label="Permalink to &quot;10.3 微信:三园区五机房&quot;">​</a></h3><ul><li>同城三个园区(深圳)</li><li>异地两个机房(上海 / 北京)</li><li>IM 数据同城三园区,跨地域容灾</li></ul><h3 id="_10-4-google-spanner-全球强一致" tabindex="-1">10.4 Google:Spanner 全球强一致 <a class="header-anchor" href="#_10-4-google-spanner-全球强一致" aria-label="Permalink to &quot;10.4 Google:Spanner 全球强一致&quot;">​</a></h3><ul><li>TrueTime API(基于原子钟 + GPS)</li><li>跨地域强一致(代价是 ~10ms 写延迟)</li><li><strong>唯一一家做到&quot;全球强一致&quot;的公司</strong></li></ul><hr><h2 id="十一、什么时候不该上多活" tabindex="-1">十一、什么时候不该上多活 <a class="header-anchor" href="#十一、什么时候不该上多活" aria-label="Permalink to &quot;十一、什么时候不该上多活&quot;">​</a></h2><h3 id="_11-1-业务规模不到" tabindex="-1">11.1 业务规模不到 <a class="header-anchor" href="#_11-1-业务规模不到" aria-label="Permalink to &quot;11.1 业务规模不到&quot;">​</a></h3><p>DAU &lt; 1000 万的业务,<strong>同城双活足够</strong>。异地多活引入的复杂度远大于带来的收益。</p><h3 id="_11-2-团队不够强" tabindex="-1">11.2 团队不够强 <a class="header-anchor" href="#_11-2-团队不够强" aria-label="Permalink to &quot;11.2 团队不够强&quot;">​</a></h3><p>异地多活要求:</p><ul><li>强大的发布系统(同时部署多 Cell)</li><li>完善的监控体系</li><li>配套的演练机制</li><li>路由 / 配置中心的稳定基础设施</li></ul><p><strong>没这些,多活反而是事故源</strong>。</p><h3 id="_11-3-业务模型不适合" tabindex="-1">11.3 业务模型不适合 <a class="header-anchor" href="#_11-3-业务模型不适合" aria-label="Permalink to &quot;11.3 业务模型不适合&quot;">​</a></h3><p>强一致业务(银行核心、清算系统)→ 异地多活意义不大,<strong>强一致跨地域延迟太大</strong>,只能用 Cell 化或冷备。</p><hr><h2 id="十二、最终架构概念图" tabindex="-1">十二、最终架构概念图 <a class="header-anchor" href="#十二、最终架构概念图" aria-label="Permalink to &quot;十二、最终架构概念图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    全球用户</span></span>
<span class="line"><span>                       ↓</span></span>
<span class="line"><span>                  GeoDNS / Anycast</span></span>
<span class="line"><span>                       ↓</span></span>
<span class="line"><span>        ┌──────────────┼──────────────┐</span></span>
<span class="line"><span>        ↓              ↓              ↓</span></span>
<span class="line"><span>   ┌────────┐    ┌────────┐     ┌────────┐</span></span>
<span class="line"><span>   │ Cell A │    │ Cell B │     │ Cell C │</span></span>
<span class="line"><span>   │ 北京    │    │ 上海    │     │ 深圳    │</span></span>
<span class="line"><span>   │--------│    │--------│     │--------│</span></span>
<span class="line"><span>   │ App    │    │ App    │     │ App    │</span></span>
<span class="line"><span>   │ DB     │    │ DB     │     │ DB     │</span></span>
<span class="line"><span>   │ Cache  │    │ Cache  │     │ Cache  │</span></span>
<span class="line"><span>   │ MQ     │    │ MQ     │     │ MQ     │</span></span>
<span class="line"><span>   └───┬────┘    └───┬────┘     └───┬────┘</span></span>
<span class="line"><span>       ↕              ↕              ↕</span></span>
<span class="line"><span>       ──── 异步数据同步层 ────────────</span></span>
<span class="line"><span>       (DB binlog / Kafka 跨 Cell 复制)</span></span></code></pre></div><hr><h2 id="十三、踩坑提醒" tabindex="-1">十三、踩坑提醒 <a class="header-anchor" href="#十三、踩坑提醒" aria-label="Permalink to &quot;十三、踩坑提醒&quot;">​</a></h2><ol><li><strong>没监控就上多活</strong>——出事时不知道哪个 Cell 错</li><li><strong>强一致业务上异地多活</strong>——必然性能崩</li><li><strong>跨 Cell 同步调用</strong>——延迟把用户体验毁掉</li><li><strong>数据冲突没处理方案</strong>——双写时数据脏</li><li><strong>不演练切流</strong>——真出事时切不过去</li><li><strong>路由层单点</strong>——路由层挂了所有 Cell 都没法用</li><li><strong>配置不统一</strong>——A B 配置不一致,行为不同</li><li><strong>异步同步无监控</strong>——同步停了 1 小时没人发现</li><li><strong>以为多活 = 高可用</strong>——多活可能更脆弱(同步链路)</li><li><strong>没&quot;备 Cell&quot;</strong>——所有 Cell 都跑业务,挂一个就丢 1/N 用户</li><li><strong>Cell 划分粒度太粗 / 太细</strong>——粗了故障域大,细了管理复杂</li><li><strong>以为团队能力够</strong>——多活需要顶级 SRE 团队 + 全套基础设施</li></ol><hr><p>下一篇:<code>26-容灾与备份.md</code>,讲灾备的&quot;两个 R&quot;——RTO(恢复时间目标)和 RPO(数据丢失容忍),备份的几种形式(全量 / 增量 / 日志),<strong>两地三中心</strong> vs <strong>三地五中心</strong>,故障演练(Game Day)和混沌工程的实战,以及为什么&quot;备份不演练 = 没有备份&quot;。</p>`,122)])])}const u=s(p,[["render",i]]);export{g as __pageData,u as default};
